package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.entity.user.UserEntity
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.NotFoundException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {
    @Transactional
    fun follow(followerId: String, followingId: String): FollowEntity {
        if (followerId == followingId) {
            throw SelfFollowException("자기 자신을 팔로우할 수 없습니다.")
        }
        userRepository.findById(followerId).orElseThrow {
            NotFoundException("존재하지 않는 유저입니다: $followerId")
        }
        userRepository.findById(followingId).orElseThrow {
            NotFoundException("존재하지 않는 유저입니다: $followingId")
        }
        if (followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)) {
            throw AlreadyFollowingException("이미 팔로우 중인 유저입니다: $followingId")
        }
        val followEntity = FollowEntity(followerId = followerId, followingId = followingId)
        return followRepository.save(followEntity)
    }

    @Transactional
    fun unfollow(followerId: String, followingId: String) {
        if (!followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)) {
            throw NotFoundException("팔로우 관계가 존재하지 않습니다: $followerId -> $followingId")
        }
        followRepository.deleteByFollowerIdAndFollowingId(followerId, followingId)
    }

    @Transactional(readOnly = true)
    fun getFollowers(userId: String): List<FollowEntity> {
        userRepository.findById(userId).orElseThrow {
            NotFoundException("존재하지 않는 유저입니다: $userId")
        }
        return followRepository.findAllByFollowingId(userId)
    }

    @Transactional(readOnly = true)
    fun getFollowing(userId: String): List<FollowEntity> {
        userRepository.findById(userId).orElseThrow {
            NotFoundException("존재하지 않는 유저입니다: $userId")
        }
        return followRepository.findAllByFollowerId(userId)
    }

    @Transactional(readOnly = true)
    fun getUserById(userId: String): UserEntity {
        return userRepository.findById(userId).orElseThrow {
            NotFoundException("존재하지 않는 유저입니다: $userId")
        }
    }
}
